SELECT generico5.anunciante AS datoscopia,   SUM(generico5.inversionus) AS temptc26225288700,   generico5.vehiculo AS vehiculo,   SUM(generico5.inversionus) AS sumcalculation0061002123102817ok,   SUM(CAST(generico5.numanuncios AS BIGINT)) AS sumnumanunciosok,   CAST(EXTRACT(YEAR FROM generico5.fecha) AS BIGINT) AS yrfechaok FROM generico5 WHERE ((generico5.anunciante IN ('BANTRAB/TODOTICKET', 'TODOTICKET', 'TODOTICKET.COM')) AND (CAST(EXTRACT(YEAR FROM generico5.fecha) AS BIGINT) IN (2014, 2015)) AND (generico5.medio = 'RADIO') AND (CAST(EXTRACT(MONTH FROM generico5.fecha) AS BIGINT) IN (1, 2, 3, 4, 5))) GROUP BY generico5.anunciante,   generico5.vehiculo,   yrfechaok;
